const sessionStore = {
  get(key) {
    const value = sessionStorage.getItem(key);
    if (!value) return;
    try {
      return JSON.parse(value);
    } catch (error) {
      return value;
    }
  },
  set(key, value) {
    if (typeof value === "string") {
      sessionStorage.setItem(key, value);
    } else {
      sessionStorage.setItem(key, JSON.stringify(value));
    }
  },
  remove(key) {
    sessionStorage.removeItem(key);
  }
};
export {
  sessionStore
};
